#include <stdio.h>
#include <limits.h>
#define MAX_C 230
#define MAX_F 23665
#define MAX_P 100000
int dist[MAX_C][MAX_C];
int main() {
    int C, F;
    scanf("%d %d", &C, &F);
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < C; j++) {
            if (i == j) {
                dist[i][j] = 0;
            } else {
                dist[i][j] = INT_MAX;
            }
        }
    }
    for (int i = 0; i < F; i++) {
        int x, y, p;
        scanf("%d %d %d", &x, &y, &p);
        x--;
        y--;
        dist[x][y] = p;
        dist[y][x] = p;
    }
    for (int k = 0; k < C; k++) {
        for (int i = 0; i < C; i++) {
            for (int j = 0; j < C; j++) {
                if (dist[i][k] != INT_MAX && dist[k][j] != INT_MAX) {
                    dist[i][j] = (dist[i][j] == INT_MAX) ? dist[i][k] + dist[k][j] : (dist[i][j] < dist[i][k] + dist[k][j] ? dist[i][j] : dist[i][k] + dist[k][j]);
                }
            }
        }
    }
    int maxCost = 0;
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < C; j++) {
            if (dist[i][j] > maxCost) {
                maxCost = dist[i][j];
            }
        }
    }
    printf("%d\n", maxCost);
    return 0;
}

