let idx = 0;
const readline = () => input[idx++];
const C = 230;
const F = 23665;
const MAX_P = 100000;
const dist = Array(C).fill().map(() => Array(C).fill(Infinity));
const [C_val, F_val] = readline().split(' ').map(Number);
for (let i = 0; i < C_val; i++) {
    dist[i][i] = 0;
}
for (let i = 0; i < F_val; i++) {
    const [x, y, p] = readline().split(' ').map(Number);
    dist[x - 1][y - 1] = p;
    dist[y - 1][x - 1] = p;
}
for (let k = 0; k < C_val; k++) {
    for (let i = 0; i < C_val; i++) {
        for (let j = 0; j < C_val; j++) {
            if (dist[i][k] !== Infinity && dist[k][j] !== Infinity) {
                dist[i][j] = Math.min(dist[i][j], dist[i][k] + dist[k][j]);
            }
        }
    }
}
let maxCost = 0;
for (let i = 0; i < C_val; i++) {
    for (let j = 0; j < C_val; j++) {
        if (dist[i][j] > maxCost) {
            maxCost = dist[i][j];
        }
    }
}
